css:
/* Suppress the standard wrapper Letter Head — we render it inline below so
   the operator's print-dialog 'No Letter Head' toggle can't strip it. */
#header-html, .letter-head, .letter-head-content { display: none !important; }

.rmax-zatca { font-family: 'Segoe UI', 'Helvetica Neue', Arial, 'Tahoma', sans-serif; font-size: 9pt; color: #000; }
.rmax-zatca table { width: 100%; border-collapse: collapse; }
.rmax-zatca td, .rmax-zatca th { padding: 4px 6px; vertical-align: top; }

/* Inline letter head wrapper */
.rz-header { margin-bottom: 4px; }
.rz-header img { max-height: 70px; }

/* Title bar — full width grey background, centered title, right-aligned page count */
.rz-title { position: relative; background: #f0f0f0; border: 1px solid #555; padding: 8px 10px; margin-top: 6px; }
.rz-title-text { text-align: center; font-size: 14pt; font-weight: bold; }
.rz-page { position: absolute; right: 10px; top: 10px; font-size: 8.5pt; font-weight: normal; }

/* Metadata + buyer key-value blocks: bordered, four-column EN/value/value/AR */
.rz-meta, .rz-buyer { border: 1px solid #555; margin-top: 6px; }
.rz-meta tr, .rz-buyer tr { border-bottom: 1px solid #ccc; }
.rz-meta tr:last-child, .rz-buyer tr:last-child { border-bottom: none; }
.rz-meta td, .rz-buyer td { border-right: 1px solid #ccc; }
.rz-meta td:last-child, .rz-buyer td:last-child { border-right: none; }
.rz-key-en { width: 18%; font-weight: bold; background: #fafafa; }
.rz-key-ar { width: 18%; font-weight: bold; background: #fafafa; direction: rtl; text-align: right; }
.rz-buyer .rz-key-en, .rz-buyer .rz-key-ar { width: 14%; }
.rz-val { width: 32%; }
.rz-buyer .rz-val { width: 36%; }
.rz-section { background: #e8e8e8; font-weight: bold; padding: 4px 6px; border-top: 1px solid #555; border-bottom: 1px solid #555; }

/* Items table: dense bordered grid, headers on grey, EN above AR per cell */
.rz-items { border: 1px solid #555; margin-top: 6px; }
.rz-items th { background: #f0f0f0; font-weight: bold; text-align: center; font-size: 8pt; border: 1px solid #555; padding: 4px 3px; }
.rz-items td { border: 1px solid #bbb; font-size: 8.5pt; padding: 3px 5px; }
.rz-ar-h { font-weight: normal; font-size: 7.5pt; display: block; margin-top: 2px; }
.rz-c-sl { width: 3%; }
.rz-c-code { width: 11%; }
.rz-c-name { width: 24%; text-align: left; }
.rz-c-qty { width: 6%; }
.rz-c-unit { width: 9%; }
.rz-c-disc { width: 7%; }
.rz-c-tax { width: 10%; }
.rz-c-vp { width: 6%; }
.rz-c-va { width: 9%; }
.rz-c-incl { width: 11%; }

/* Totals — QR on left, totals stack on right */
.rz-totals-wrap { margin-top: 6px; }
.rz-totals-wrap td { border: 0; padding: 0; }
.rz-qr-cell { width: 25%; vertical-align: top; text-align: center; padding: 6px; }
.rz-totals-cell { vertical-align: top; }
.rz-totals { border: 1px solid #555; }
.rz-totals td { border-bottom: 1px solid #ccc; padding: 4px 6px; }
.rz-totals tr:last-child td { border-bottom: none; }
.rz-tot-en { width: 35%; font-weight: 600; }
.rz-tot-ar { width: 50%; }
.rz-tot-num { width: 15%; font-weight: 600; }
.rz-tot-grand td { background: #f0f0f0; font-weight: bold; font-size: 10pt; }
.rz-totals-ar-head { float: right; }
.rz-qr { width: 110px; height: 110px; }

.rz-rtl { direction: rtl; text-align: right; }
.rz-center { text-align: center; }
.rz-right { text-align: right; }
.rz-bold { font-weight: bold; }

/* Footer + banks */
.rz-footer { margin-top: 14px; }
.rz-footer td { border-top: 1px solid #ccc; padding-top: 6px; }
.rz-footer .rz-w25 { width: 25%; }
.rz-banks { margin-top: 6px; }
.rz-banks td { padding: 3px 6px; }

@media print { .rmax-zatca { font-size: 9pt; } }
